import {
  workflow,
  trigger,
  node,
} from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' },
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'artifact card test',
    parameters: {
      assignments: {
        assignments: [],
      },
    },
  },
});

export default workflow('id', 'artifact card test')
  .add(manualTrigger)
  .to(setNode);
